#include<bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
	il ll read()
	{
		ll x=0,f=1;char ch=gc();
		wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
		wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
		return x*f;
	}
	void write(ll x)
	{
		if(x<0)pc('-'),x=-x;
		if(x>9)write(x/10);
		pc(x%10+'0');
	}
	void writeln(ll x)
	{
		write(x);
		puts("");
		return;
	}
}
using NP phigrOS;
CI N=200005;
int n,mx,c[N];
vector<int>e[N];
PII dfs(int u,int f)
{
	int w=0,b=0;
	FOI(v,e[u])
	{
		if(v==f)continue;
		PII t=dfs(v,u);
		int wl=t.fst,bl=t.snd;
		if(b!=0)mx=max(mx,wl+b);
		if(w!=0)mx=max(mx,bl+w);
		w=max(w,wl);
		b=max(b,bl);
	}
	if(c[u]==0)mx=max(mx,b);
	else mx=max(mx,w);
	PII r;
	r.fst=r.snd=-1e9;
	if(c[u]==0)r.fst=1;
	else r.snd=1;
	if(w!=0)r.fst=w+1;
	if(b!=0)r.snd=b+1;
	return r;
}
signed main(void)
{
	n=read();
	FOR(i,1,n)c[i]=read();
	FOR(i,1,n-1)
	{
		int u,v;
		u=read();v=read();
		e[u].pb(v);
		e[v].pb(u);
	}
	dfs(1,0);
	writeln(mx);
	return false;
}
